SELECT JSONB_AGG(JSONB_BUILD_OBJECT('email', "contact_emails"."email", 'is_primary', "contact_emails"."is_primary")) AS contact_emails, JSONB_AGG(JSONB_BUILD_OBJECT('phone_number_raw', "contact_phone_numbers"."phone_number_raw")) AS contact_phone_numbers FROM contacts LEFT JOIN LATERAL (SELECT "joined_contact_emails"."email", "joined_contact_emails"."is_primary" FROM "contact_emails" "joined_contact_emails" WHERE (joined_contact_emails.tombstone = 0) AND "joined_contact_emails"."contact_id" = "contacts"."id" ) AS "contact_emails" ON TRUE LEFT JOIN LATERAL (SELECT "joined_contact_phone_numbers"."phone_number_raw" FROM "contact_phone_numbers" "joined_contact_phone_numbers" WHERE (joined_contact_phone_numbers.tombstone = 0) AND "joined_contact_phone_numbers"."contact_id" = "contacts"."id" ) AS "contact_phone_numbers" ON TRUE LEFT JOIN LATERAL (SELECT "joined_created_by_account_organizations"."id", "joined_created_by_account_organizations"."contact_id" FROM "account_organizations" "joined_created_by_account_organizations" WHERE (joined_created_by_account_organizations.tombstone = 0) AND "joined_created_by_account_organizations"."id" = "contacts"."created_by" ) AS "created_by_account_organizations" ON TRUE LEFT JOIN LATERAL (SELECT "joined_created_by"."id", "joined_created_by"."first_name", "joined_created_by"."last_name" FROM "contacts" "joined_created_by" WHERE (joined_created_by.tombstone = 0) AND "joined_created_by"."id" = "created_by_account_organizations"."contact_id" ) AS "created_by" ON TRUE LEFT JOIN LATERAL (SELECT "joined_updated_by_account_organizations"."id", "joined_updated_by_account_organizations"."contact_id" FROM "account_organizations" "joined_updated_by_account_organizations" WHERE (joined_updated_by_account_organizations.tombstone = 0) AND "joined_updated_by_account_organizations"."id" = "contacts"."updated_by" ) AS "updated_by_account_organizations" ON TRUE LEFT JOIN LATERAL (SELECT "joined_updated_by"."id", "joined_updated_by"."first_name", "joined_updated_by"."last_name" FROM "contacts" "joined_updated_by" WHERE (joined_updated_by.tombstone = 0) AND "joined_updated_by"."id" = "updated_by_account_organizations"."contact_id" ) AS "updated_by" ON TRUE WHERE (contacts.tombstone = 0) AND COALESCE("contacts"."created_date"::text || "contacts"."created_time"::text) ILIKE '%08/20/2025 14%' AND contacts.status::text IN ('Active', 'Draft') GROUP BY contacts.id, "contacts"."categories", "contacts"."organization_id", "contacts"."first_name", "contacts"."middle_name", "contacts"."last_name", "contact_phone_numbers"."phone_number_raw", "created_by"."id", "created_by"."first_name", "created_by"."last_name", "updated_by"."id", "updated_by"."first_name", "updated_by"."last_name", "contacts"."code", "contacts"."categories", "contacts"."organization_id", "contacts"."first_name", "contacts"."middle_name", "contacts"."last_name", "contacts"."status", "contacts"."created_date", "contacts"."updated_date", "contacts"."created_time", "contacts"."updated_time", "contacts"."created_by", "contacts"."updated_by", "contacts"."previous_status", "contact_emails"."email", "contact_emails"."is_primary", "created_by_account_organizations"."id", "created_by_account_organizations"."contact_id", "updated_by_account_organizations"."id", "updated_by_account_organizations"."contact_id", "contact_emails"."email", "contact_emails"."is_primary", "contact_phone_numbers"."phone_number_raw", "created_by"."first_name", "created_by"."last_name", "updated_by"."first_name", "updated_by"."last_name", "contact"."created_date", "contact"."created_time", "contact"."updated_date", "contact"."updated_time" ORDER BY LOWER(contacts.status) ASC LIMIT 100